import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DAYS, PERIOD_TIMES } from '../data/initialData';

export default function TimetablePage() {

  const { timetable, staff, addTimetableEntry, removeTimetableEntry, currentUser } = useApp();

  const isAdmin = currentUser.role === 'admin';

  const [selectedStaff, setSelectedStaff] = useState(
    !isAdmin ? (currentUser._id || currentUser.id) : (staff[0]?._id || staff[0]?.id || '')
  );

  const [newEntry, setNewEntry] = useState({
    day: 'Monday',
    period: 1,
    class: ''
  });

  const [showAdd, setShowAdd] = useState(false);

  const displayStaffId = isAdmin
    ? selectedStaff
    : (currentUser._id || currentUser.id);

  const slots = timetable[displayStaffId] || [];

  const selectedStaffMember = staff.find(
    s => (s._id || s.id) === displayStaffId
  );

  const handleAdd = () => {

    if (!newEntry.class.trim()) {
      alert('Please enter class name');
      return;
    }

    addTimetableEntry(displayStaffId, {
      ...newEntry,
      period: Number(newEntry.period),
      time: PERIOD_TIMES[newEntry.period]
    });

    setNewEntry({
      day: 'Monday',
      period: 1,
      class: ''
    });

    setShowAdd(false);
  };

  const gridData = {};

  DAYS.forEach(day => {
    gridData[day] = {};
    [1, 2, 3, 4].forEach(p => {
      gridData[day][p] = null;
    });
  });

  slots.forEach((slot, idx) => {
    if (gridData[slot.day]) {
      gridData[slot.day][slot.period] = { ...slot, idx };
    }
  });

  return (
    <div style={{ padding: 30 }}>

      <h1>📅 Timetable</h1>

      {isAdmin && (
        <div style={{ marginBottom: 20 }}>
          {staff.map(t => {

            const id = t._id || t.id;

            return (
              <button
                key={id}
                onClick={() => setSelectedStaff(id)}
                style={{
                  marginRight: 10,
                  padding: '8px 14px',
                  background: displayStaffId === id ? '#2563eb' : '#eee',
                  color: displayStaffId === id ? '#fff' : '#000',
                  border: 'none',
                  borderRadius: 6,
                  cursor: 'pointer'
                }}
              >
                {t.name}
              </button>
            );
          })}
        </div>
      )}

      {isAdmin && (
        <button
          onClick={() => setShowAdd(!showAdd)}
          style={{
            marginBottom: 20,
            padding: '8px 16px',
            background: '#16a34a',
            color: '#fff',
            border: 'none',
            borderRadius: 6,
            cursor: 'pointer'
          }}
        >
          + Add Period
        </button>
      )}

      {showAdd && isAdmin && (

        <div style={{ marginBottom: 20 }}>

          <select
            value={newEntry.day}
            onChange={e => setNewEntry({ ...newEntry, day: e.target.value })}
          >
            {DAYS.map(d => (
              <option key={d}>{d}</option>
            ))}
          </select>

          <select
            value={newEntry.period}
            onChange={e => setNewEntry({ ...newEntry, period: e.target.value })}
          >
            {[1,2,3,4].map(p => (
              <option key={p} value={p}>
                Period {p} ({PERIOD_TIMES[p]})
              </option>
            ))}
          </select>

          <input
            placeholder="Class"
            value={newEntry.class}
            onChange={e => setNewEntry({ ...newEntry, class: e.target.value })}
          />

          <button onClick={handleAdd}>
            Save
          </button>

        </div>
      )}

      <table border="1" cellPadding="10">

        <thead>

          <tr>
            <th>Day / Period</th>

            {[1,2,3,4].map(p => (
              <th key={p}>
                Period {p}
                <br />
                {PERIOD_TIMES[p]}
              </th>
            ))}

          </tr>

        </thead>

        <tbody>

          {DAYS.map(day => (

            <tr key={day}>

              <td>{day}</td>

              {[1,2,3,4].map(p => {

                const slot = gridData[day][p];

                return (

                  <td key={p}>

                    {slot ? (

                      <div>

                        Class {slot.class}

                        {isAdmin && (
                          <button
                            onClick={() => removeTimetableEntry(displayStaffId, slot.idx)}
                          >
                            ❌
                          </button>
                        )}

                      </div>

                    ) : '—'}

                  </td>

                );

              })}

            </tr>

          ))}

        </tbody>

      </table>

      <div style={{ marginTop: 20 }}>
        Total Periods: {slots.length}
      </div>

    </div>
  );
}
